// n8n Code node (Node.js)
// Builds a "VA Logistics + Schedule" email from the Airtable webhook payload
// Layout: single Placement Details table with 2 columns (label | value)

function getField(fields, key, fb = "") {
  const raw = fields[key];
  if (raw === undefined || raw === null) return fb;

  if (Array.isArray(raw)) {
    if (raw.length === 0) return fb;
    const first = raw[0];
    if (first === null || first === undefined) return fb;

    if (typeof first === "object") {
      if ("name" in first) return String(first.name);
      return JSON.stringify(first);
    }
    return String(first);
  }

  if (typeof raw === "object") {
    if ("name" in raw) return String(raw.name);
    return JSON.stringify(raw);
  }

  return String(raw);
}

function formatDate(value) {
  if (!value) return "";
  const d = new Date(value);
  if (Number.isNaN(d.getTime())) return String(value);
  return d.toLocaleDateString("en-US", {
    year: "numeric",
    month: "long",
    day: "numeric",
  });
}

return $input.all().map(item => {
  // Support both "body" payloads and plain json
  const root = item.json.body || item.json;
  const fields = root.fields || root;

  // --- Core fields ---
  const vaName =
    getField(fields, "Placed VA") ||
    getField(fields, "Virtual Assistant") ||
    getField(fields, "VA Name") ||
    getField(fields, "placedVA");

  const svEmail =
    getField(fields, "SV Email") ||
    getField(fields, "svEmail");

  const vaStartDate = formatDate(
    fields["VA Start Date"] || fields["vaStartDate"]
  );

  // --- Logistics (supports text, arrays, Airtable linked records) ---
  let logisticsField =
    fields["Logistics For VA"] ||
    fields["Logistics for VA"] ||
    fields["vaLogistics"];

  let logisticsLines = [];

  if (Array.isArray(logisticsField)) {
    for (const entry of logisticsField) {
      if (entry == null) continue;
      if (typeof entry === "string" || typeof entry === "number") {
        logisticsLines.push(String(entry));
      } else if (typeof entry === "object") {
        if ("name" in entry) logisticsLines.push(String(entry.name));
        else logisticsLines.push(JSON.stringify(entry));
      }
    }
  } else if (typeof logisticsField === "string") {
    logisticsLines = logisticsField
      .split(/\r?\n/)
      .map(l => l.replace(/^[-•\u2022]\s*/, "").trim())
      .filter(Boolean);
  } else if (logisticsField != null) {
    logisticsLines.push(String(logisticsField));
  }

  const logisticsHtml = logisticsLines.length
    ? `<ul style="margin:4px 0 0 0;padding-left:20px;">${logisticsLines
        .map(line => `<li>${line}</li>`)
        .join("")}</ul>`
    : "TBD";

  // --- Schedule: use Day 1–Day 5 Schedule fields ---
  const dayFieldDefs = [
    { label: "Day 1", keys: ["Day 1 Schedule", "day1Schedule", "Day1Schedule", "day1"] },
    { label: "Day 2", keys: ["Day 2 Schedule", "day2Schedule", "Day2Schedule", "day2"] },
    { label: "Day 3", keys: ["Day 3 Schedule", "day3Schedule", "Day3Schedule", "day3"] },
    { label: "Day 4", keys: ["Day 4 Schedule", "day4Schedule", "Day4Schedule", "day4"] },
    { label: "Day 5", keys: ["Day 5 Schedule", "day5Schedule", "Day5Schedule", "day5"] },
  ];

  const scheduleRows = [];

  for (const def of dayFieldDefs) {
    let raw = "";
    for (const key of def.keys) {
      raw = getField(fields, key);
      if (raw) break;
    }
    if (!raw) continue;

    let dayLabel = def.label;
    let hours = raw;

    // If you store "MONDAY | 8 AM - 5 PM CST", respect that structure
    const parts = raw.split("|");
    if (parts.length > 1) {
      dayLabel = (parts[0] || def.label).trim();
      hours = (parts[1] || "").trim();
    }

    if (!dayLabel && !hours) continue;

    scheduleRows.push({
      day: dayLabel,
      hours,
    });
  }

  const scheduleHtml = scheduleRows.length
    ? `
      <table cellpadding="0" cellspacing="0" style="border-collapse:collapse;font-size:13px;margin-top:4px;">
        ${scheduleRows
          .map(
            r => `
          <tr>
            <td style="padding:4px 8px;border:1px solid #e0e0e0;background-color:#fff7d9;white-space:nowrap;">${r.day}</td>
            <td style="padding:4px 12px;border:1px solid #e0e0e0;white-space:nowrap;">${r.hours}</td>
          </tr>`
          )
          .join("")}
      </table>`
    : "TBD";

  // --- Email subject ---
  const subject = `VA Logistics – ${vaName || "Virtual Assistant"}`;

  // --- Styles for main 2-column table ---
  const labelCell =
    "border:1px solid #e0e0e0;padding:10px 14px;width:30%;background-color:#f2f2f2;font-weight:bold;vertical-align:top;";
  const valueCell =
    "border:1px solid #e0e0e0;padding:10px 14px;vertical-align:top;";

  const html = `<!DOCTYPE html>
<html>
  <head>
    <meta charset="utf-8" />
    <title>${subject}</title>
  </head>
  <body style="margin:0;padding:24px;font-family:Arial,Helvetica,sans-serif;font-size:14px;background-color:#f5f5f5;">
    <table align="center" width="650" cellpadding="0" cellspacing="0" style="background-color:#ffffff;border-collapse:collapse;margin:0 auto;">
      <tr>
        <td style="padding:24px;">
          <p style="margin:0 0 8px 0;">Hi,</p>
          <p style="margin:0 0 12px 0;">
            Thank you very much for your time and congratulations on hiring your Virtual Assistant in Scale Virtually!
          </p>
          <p style="margin:0 0 20px 0;">
            Before we get started on your VA, here are some follow-ups and logistics that we'll need from you:
          </p>

          <table width="100%" cellpadding="0" cellspacing="0" style="border-collapse:collapse;font-size:13px;margin-top:4px;">
            <tr>
              <td colspan="2"
                  style="background-color:#f7941d;
                         color:#ffffff;
                         font-weight:bold;
                         padding:10px 14px;
                         text-align:center;
                         font-size:14px;
                         text-transform:uppercase;">
                PLACEMENT DETAILS
              </td>
            </tr>

            <tr>
              <td style="${labelCell}">Logistics for VA</td>
              <td style="${valueCell}">${logisticsHtml}</td>
            </tr>

            <tr>
              <td style="${labelCell}">Schedule for VA</td>
              <td style="${valueCell}">${scheduleHtml}</td>
            </tr>

            <tr>
              <td style="${labelCell}">VA Name</td>
              <td style="${valueCell}">${vaName || "TBD"}</td>
            </tr>

            <tr>
              <td style="${labelCell}">SV Email</td>
              <td style="${valueCell}">
                ${
                  svEmail
                    ? `<a href="mailto:${svEmail}" style="color:#1976d2;">${svEmail}</a>`
                    : "TBD"
                }
              </td>
            </tr>

            <tr>
              <td style="${labelCell}">VA Start Date</td>
              <td style="${valueCell}">${vaStartDate || "TBD"}</td>
            </tr>
          </table>

          <p style="margin-top:20px;">
            You will also receive a Docusign that you will need to complete before the VA start date with just a confirmation on the agreement that you have with Scale Virtually.
          </p>

          <p style="margin-top:8px;">
            Please don't hesitate if there are questions or clarifications. Looking forward to hearing from you soon!
          </p>
        </td>
      </tr>
    </table>
  </body>
</html>`;

  return {
    json: {
      subject,
      email_html: html,
    },
  };
});

